# --- GraphQL Types ---

class ReviewType(graphene.ObjectType):
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user_id = graphene.ID(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String(required=True)
    comment = graphene.String()
    created_at = graphene.String()
    updated_at = graphene.String()
    helpful_votes = graphene.Int()
    verified_purchase = graphene.Boolean()
    user = graphene.Field(lambda: UserType)
    product = graphene.Field(lambda: ProductType)

    def resolve_user(self, info):
        user_data = next((u for u in USERS if u["id"] == self.user_id), None)
        if user_data:
            return UserType(**user_data)
        return None

    def resolve_product(self, info):
        product_data = next((p for p in PRODUCTS if p["id"] == self.product_id), None)
        if product_data:
            return ProductType(**product_data)
        return None


class UserType(graphene.ObjectType):
    id = graphene.ID(required=True)
    username = graphene.String(required=True)
    email = graphene.String(required=True)
    display_name = graphene.String()
    joined_at = graphene.String()
    reviews = graphene.List(ReviewType)
    review_count = graphene.Int()
    average_rating_given = graphene.Float()

    def resolve_reviews(self, info):
        user_reviews = [r for r in REVIEWS if r["user_id"] == self.id]
        return [ReviewType(**r) for r in user_reviews]

    def resolve_review_count(self, info):
        return len([r for r in REVIEWS if r["user_id"] == self.id])

    def resolve_average_rating_given(self, info):
        user_reviews = [r for r in REVIEWS if r["user_id"] == self.id]
        if not user_reviews:
            return None
        return sum(r["rating"] for r in user_reviews) / len(user_reviews)


class CategoryType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    slug = graphene.String()
    parent_id = graphene.ID()
    parent = graphene.Field(lambda: CategoryType)
    subcategories = graphene.List(lambda: CategoryType)
    products = graphene.List(lambda: ProductType, is_active=graphene.Boolean())
    product_count = graphene.Int()

    def resolve_parent(self, info):
        if self.parent_id:
            parent_data = next((c for c in CATEGORIES if c["id"] == self.parent_id), None)
            if parent_data:
                return CategoryType(**parent_data)
        return None

    def resolve_subcategories(self, info):
        subs = [c for c in CATEGORIES if c["parent_id"] == self.id]
        return [CategoryType(**c) for c in subs]

    def resolve_products(self, info, is_active=None):
        # Get products in this category and all subcategories
        category_ids = [self.id]
        sub_cats = [c for c in CATEGORIES if c["parent_id"] == self.id]
        category_ids.extend([c["id"] for c in sub_cats])

        filtered = [p for p in PRODUCTS if p["category_id"] in category_ids]
        if is_active is not None:
            filtered = [p for p in filtered if p["is_active"] == is_active]
        return [ProductType(**p) for p in filtered]

    def resolve_product_count(self, info):
        category_ids = [self.id]
        sub_cats = [c for c in CATEGORIES if c["parent_id"] == self.id]
        category_ids.extend([c["id"] for c in sub_cats])
        return len([p for p in PRODUCTS if p["category_id"] in category_ids and p["is_active"]])


class PriceRangeType(graphene.ObjectType):
    min_price = graphene.Float()
    max_price = graphene.Float()
    currency = graphene.String()


class ReviewSummaryType(graphene.ObjectType):
    average_rating = graphene.Float()
    total_reviews = graphene.Int()
    rating_distribution = graphene.List(graphene.Int, description="Count of reviews for ratings 1-5")


class ProductType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    currency = graphene.String()
    sku = graphene.String()
    stock_quantity = graphene.Int()
    category_id = graphene.ID()
    brand = graphene.String()
    is_active = graphene.Boolean()
    created_at = graphene.String()
    updated_at = graphene.String()
    tags = graphene.List(graphene.String)
    weight = graphene.Float()
    images = graphene.List(graphene.String)
    category = graphene.Field(CategoryType)
    reviews = graphene.List(ReviewType, limit=graphene.Int(), sort_by=graphene.String())
    review_summary = graphene.Field(ReviewSummaryType)
    in_stock = graphene.Boolean()
    related_products = graphene.List(lambda: ProductType, limit=graphene.Int(default_value=5))

    def resolve_category(self, info):
        cat_data = next((c for c in CATEGORIES if c["id"] == self.category_id), None)
        if cat_data:
            return CategoryType(**cat_data)
        return None

    def resolve_reviews(self, info, limit=None, sort_by=None):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]

        if sort_by == "rating_desc":
            product_reviews.sort(key=lambda r: r["rating"], reverse=True)
        elif sort_by == "rating_asc":
            product_reviews.sort(key=lambda r: r["rating"])
        elif sort_by == "newest":
            product_reviews.sort(key=lambda r: r["created_at"], reverse=True)
        elif sort_by == "most_helpful":
            product_reviews.sort(key=lambda r: r["helpful_votes"], reverse=True)
        else:
            product_reviews.sort(key=lambda r: r["created_at"], reverse=True)

        if limit:
            product_reviews = product_reviews[:limit]

        return [ReviewType(**r) for r in product_reviews]

    def resolve_review_summary(self, info):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]
        if not product_reviews:
            return ReviewSummaryType(average_rating=0, total_reviews=0, rating_distribution=[0, 0, 0, 0, 0])

        total = len(product_reviews)
        avg = sum(r["rating"] for r in product_reviews) / total
        distribution = [0, 0, 0, 0, 0]
        for r in product_reviews:
            distribution[r["rating"] - 1] += 1

        return ReviewSummaryType(
            average_rating=round(avg, 2),
            total_reviews=total,
            rating_distribution=distribution
        )

    def resolve_in_stock(self, info):
        return self.stock_quantity > 0 if self.stock_quantity is not None else False

    def resolve_related_products(self, info, limit=5):
        # Find related products by same category, excluding self
        related = [p for p in PRODUCTS if p["category_id"] == self.category_id and p["id"] != self.id and p["is_active"]]

        # Also find products with overlapping tags
        if hasattr(self, 'tags') and self.tags:
            my_tags = set(self.tags)
            for p in PRODUCTS:
                if p["id"] != self.id and p["is_active"] and p["id"] not in [r["id"] for r in related]:
                    if set(p.get("tags", [])) & my_tags:
                        related.append(p)

        related = related[:limit]
        return [ProductType(**p) for p in related]


class ProductConnection(graphene.ObjectType):
    """Paginated product results"""
    items = graphene.List(ProductType)
    total_count = graphene.Int()
    page = graphene.Int()
    page_size = graphene.Int()
    has_next_page = graphene.Boolean()
    has_previous_page = graphene.Boolean()


class ProductSortEnum(graphene.Enum):
    PRICE_ASC = "price_asc"
    PRICE_DESC = "price_desc"
    NAME_ASC = "name_asc"
    NAME_DESC = "name_desc"
    NEWEST = "newest"
    OLDEST = "oldest"
    RATING = "rating"


class CatalogStatsType(graphene.ObjectType):
    total_products = graphene.Int()
    active_products = graphene.Int()
    total_categories = graphene.Int()
    total_reviews = graphene.Int()
    total_users = graphene.Int()
    average_product_price = graphene.Float()
    price_range = graphene.Field(PriceRangeType)


# --- Queries ---

class Query(graphene.ObjectType):
    # Product queries
    product = graphene.Field(ProductType, id=graphene.ID(required=True))
    product_by_sku = graphene.Field(ProductType, sku=graphene.String(required=True))
    products = graphene.Field(
        ProductConnection,
        page=graphene.Int(default_value=1),
        page_size=graphene.Int(default_value=10),
        category_id=graphene.ID(),
        brand=graphene.String(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        search=graphene.String(),
        is_active=graphene.Boolean(default_value=True),
        in_stock=graphene.Boolean(),
        tags=graphene.List(graphene.String),
        sort_by=ProductSortEnum(),
    )
    all_products = graphene.List(
        ProductType,
        is_active=graphene.Boolean(),
        description="Get all products without pagination"
    )

    # Category queries
    category = graphene.Field(CategoryType, id=graphene.ID(), slug=graphene.String())
    categories = graphene.List(CategoryType, top_level_only=graphene.Boolean(default_value=False))

    # Review queries
    review = graphene.Field(ReviewType, id=graphene.ID(required=True))
    reviews = graphene.List(
        ReviewType,
        product_id=graphene.ID(),
        user_id=graphene.ID(),
        min_rating=graphene.Int(),
        verified_only=graphene.Boolean(default_value=False),
        limit=graphene.Int(default_value=20),
        sort_by=graphene.String(default_value="newest"),
    )

    # User queries
    user = graphene.Field(UserType, id=graphene.ID(), username=graphene.String())
    users = graphene.List(UserType)

    # Stats
    catalog_stats = graphene.Field(CatalogStatsType)

    # Search
    search_products = graphene.List(
        ProductType,
        query=graphene.String(required=True),
        limit=graphene.Int(default_value=10),
    )

    # Product resolvers
    def resolve_product(self, info, id):
        product_data = next((p for p in PRODUCTS if p["id"] == id), None)
        if product_data:
            return ProductType(**product_data)
        return None

    def resolve_product_by_sku(self, info, sku):
        product_data = next((p for p in PRODUCTS if p["sku"] == sku), None)
        if product_data:
            return ProductType(**product_data)
        return None

    def resolve_products(self, info, page=1, page_size=10, category_id=None, brand=None,
                         min_price=None, max_price=None, search=None, is_active=True,
                         in_stock=None, tags=None, sort_by=None):
        filtered = list(PRODUCTS)

        # Apply filters
        if is_active is not None:
            filtered = [p for p in filtered if p["is_active"] == is_active]

        if category_id:
            # Include subcategories
            cat_ids = [category_id]
            sub_cats = [c for c in CATEGORIES if c["parent_id"] == category_id]
            cat_ids.extend([c["id"] for c in sub_cats])
            filtered = [p for p in filtered if p["category_id"] in cat_ids]

        if brand:
            filtered = [p for p in filtered if p["brand"].lower() == brand.lower()]

        if min_price is not None:
            filtered = [p for p in filtered if p["price"] >= min_price]

        if max_price is not None:
            filtered = [p for p in filtered if p["price"] <= max_price]

        if in_stock is not None:
            if in_stock:
                filtered = [p for p in filtered if p["stock_quantity"] > 0]
            else:
                filtered = [p for p in filtered if p["stock_quantity"] == 0]

        if tags:
            tag_set = set(t.lower() for t in tags)
            filtered = [p for p in filtered if tag_set & set(t.lower() for t in p.get("tags", []))]

        if search:
            search_lower = search.lower()
            filtered = [p for p in filtered if
                        search_lower in p["name"].lower() or
                        search_lower in p["description"].lower() or
                        search_lower in p["brand"].lower() or
                        any(search_lower in tag.lower() for tag in p.get("tags", []))]

        # Apply sorting
        if sort_by:
            sort_val = sort_by if isinstance(sort_by, str) else sort_by.value
            if sort_val == "price_asc":
                filtered.sort(key=lambda p: p["price"])
            elif sort_val == "price_desc":
                filtered.sort(key=lambda p: p["price"], reverse=True)
            elif sort_val == "name_asc":
                filtered.sort(key=lambda p: p["name"].lower())
            elif sort_val == "name_desc":
                filtered.sort(key=lambda p: p["name"].lower(), reverse=True)
            elif sort_val == "newest":
                filtered.sort(key=lambda p: p["created_at"], reverse=True)
            elif sort_val == "oldest":
                filtered.sort(key=lambda p: p["created_at"])
            elif sort_val == "rating":
                def avg_rating(product):
                    reviews = [r for r in REVIEWS if r["product_id"] == product["id"]]
                    if not reviews:
                        return 0
                    return sum(r["rating"] for r in reviews) / len(reviews)
                filtered.sort(key=avg_rating, reverse=True)

        total_count = len(filtered)
        start = (page - 1) * page_size
        end = start + page_size
        page_items = filtered[start:end]

        return ProductConnection(
            items=[ProductType(**p) for p in page_items],
            total_count=total_count,
            page=page,
            page_size=page_size,
            has_next_page=end < total_count,
            has_previous_page=page > 1,
        )

    def resolve_all_products(self, info, is_active=None):
        filtered = list(PRODUCTS)
        if is_active is not None:
            filtered = [p for p in filtered if p["is_active"] == is_active]
        return [ProductType(**p) for p in filtered]

    # Category resolvers
    def resolve_category(self, info, id=None, slug=None):
        if id:
            cat_data = next((c for c in CATEGORIES if c["id"] == id), None)
        elif slug:
            cat_data = next((c for c in CATEGORIES if c["slug"] == slug), None)
        else:
            return None
        if cat_data:
            return CategoryType(**cat_data)
        return None

    def resolve_categories(self, info, top_level_only=False):
        if top_level_only:
            filtered = [c for c in CATEGORIES if c["parent_id"] is None]
        else:
            filtered = CATEGORIES
        return [CategoryType(**c) for c in filtered]

    # Review resolvers
    def resolve_review(self, info, id):
        review_data = next((r for r in REVIEWS if r["id"] == id), None)
        if review_data:
            return ReviewType(**review_data)
        return None

    def resolve_reviews(self, info, product_id=None, user_id=None, min_rating=None,
                        verified_only=False, limit=20, sort_by="newest"):
        filtered = list(REVIEWS)

        if product_id:
            filtered = [r for r in filtered if r["product_id"] == product_id]

        if user_id:
            filtered = [r for r in filtered if r["user_id"] == user_id]

        if min_rating is not None:
            filtered = [r for r in filtered if r["rating"] >= min_rating]

        if verified_only:
            filtered = [r for r in filtered if r["verified_purchase"]]

        if sort_by == "newest":
            filtered.sort(key=lambda r: r["created_at"], reverse=True)
        elif sort_by == "oldest":
            filtered.sort(key=lambda r: r["created_at"])
        elif sort_by == "rating_desc":
            filtered.sort(key=lambda r: r["rating"], reverse=True)
        elif sort_by == "rating_asc":
            filtered.sort(key=lambda r: r["rating"])
        elif sort_by == "most_helpful":
            filtered.sort(key=lambda r: r["helpful_votes"], reverse=True)

        filtered = filtered[:limit]
        return [ReviewType(**r) for r in filtered]

    # User resolvers
    def resolve_user(self, info, id=None, username=None):
        if id:
            user_data = next((u for u in USERS if u["id"] == id), None)
        elif username:
            user_data = next((u for u in USERS if u["username"] == username), None)
        else:
            return None
        if user_data:
            return UserType(**user_data)
        return None

    def resolve_users(self, info):
        return [UserType(**u) for u in USERS]

    # Stats resolver
    def resolve_catalog_stats(self, info):
        active_products = [p for p in PRODUCTS if p["is_active"]]
        prices = [p["price"] for p in active_products]

        return CatalogStatsType(
            total_products=len(PRODUCTS),
            active_products=len(active_products),
            total_categories=len(CATEGORIES),
            total_reviews=len(REVIEWS),
            total_users=len(USERS),
            average_product_price=round(sum(prices) / len(prices), 2) if prices else 0,
            price_range=PriceRangeType(
                min_price=min(prices) if prices else 0,
                max_price=max(prices) if prices else 0,
                currency="USD"
            )
        )

    # Search resolver
    def resolve_search_products(self, info, query, limit=10):
        query_lower = query.lower()
        scored_products = []

        for p in PRODUCTS:
            if not p["is_active"]:
                continue

            score = 0
            if query_lower in p["name"].lower():
                score += 10
            if query_lower == p["name"].lower():
                score += 20
            if query_lower in p["description"].lower():
                score += 5
            if query_lower == p["brand"].lower():
                score += 8
            if query_lower in p["brand"].lower():
                score += 3
            for tag in p.get("tags", []):
                if query_lower in tag.lower():
                    score += 4
            if query_lower in p["sku"].lower():
                score += 15

            if score > 0:
                scored_products.append((score, p))

        scored_products.sort(key=lambda x: x[0], reverse=True)
        results = [ProductType(**p) for _, p in scored_products[:limit]]
        return results


# --- Mutations ---

class CreateReviewInput(graphene.InputObjectType):
    product_id = graphene.ID(required=True)
    user_id = graphene.ID(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String(required=True)
    comment = graphene.String()
    verified_purchase = graphene.Boolean(default_value=False)


class CreateReview(graphene.Mutation):
    class Arguments:
        input = CreateReviewInput(required=True)

    review = graphene.Field(ReviewType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, input):
        # Validate rating
        if input.rating < 1 or input.rating > 5:
            return CreateReview(review=None, success=False, message="Rating must be between 1 and 5")

        # Validate product exists
        product = next((p for p in PRODUCTS if p["id"] == input.product_id), None)
        if not product:
            return CreateReview(review=None, success=False, message="Product not found")

        # Validate user exists
        user = next((u for u in USERS if u["id"] == input.user_id), None)
        if not user:
            return CreateReview(review=None, success=False, message="User not found")

        # Check if user already reviewed this product
        existing = next((r for r in REVIEWS if r["product_id"] == input.product_id and r["user_id"] == input.user_id), None)
        if existing:
            return CreateReview(review=None, success=False, message="User has already reviewed this product")

        now = datetime.utcnow().isoformat()
        new_id = str(max(int(r["id"]) for r in REVIEWS) + 1)

        new_review = {
            "id": new_id,
            "product_id": input.product_id,
            "user_id": input.user_id,
            "rating": input.rating,
            "title": input.title,
            "comment": input.comment or "",
            "created_at": now,
            "updated_at": now,
            "helpful_votes": 0,
            "verified_purchase": input.verified_purchase,
        }

        REVIEWS.append(new_review)
        return CreateReview(review=ReviewType(**new_review), success=True, message="Review created successfully")


class UpdateReview(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)
        rating = graphene.Int()
        title = graphene.String()
        comment = graphene.String()

    review = graphene.Field(ReviewType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, id, rating=None, title=None, comment=None):
        review_data = next((r for r in REVIEWS if r["id"] == id), None)
        if not review_data:
            return UpdateReview(review=None, success=False, message="Review not found")

        if rating is not None:
            if rating < 1 or rating > 5:
                return UpdateReview(review=None, success=False, message="Rating must be between 1 and 5")
            review_data["rating"] = rating

        if title is not None:
            review_data["title"] = title

        if comment is not None:
            review_data["comment"] = comment

        review_data["updated_at"] = datetime.utcnow().isoformat()

        return UpdateReview(review=ReviewType(**review_data), success=True, message="Review updated successfully")


class DeleteReview(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)

    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, id):
        review_data = next((r for r in REVIEWS if r["id"] == id), None)
        if not review_data:
            return DeleteReview(success=False, message="Review not found")

        REVIEWS.remove(review_data)
        return DeleteReview(success=True, message="Review deleted successfully")


class VoteReviewHelpful(graphene.Mutation):
    class Arguments:
        review_id = graphene.ID(required=True)

    review = graphene.Field(ReviewType)
    success = graphene.Boolean()

    def mutate(self, info, review_id):
        review_data = next((r for r in REVIEWS if r["id"] == review_id), None)
        if not review_data:
            return VoteReviewHelpful(review=None, success=False)

        review_data["helpful_votes"] += 1
        return VoteReviewHelpful(review=ReviewType(**review_data), success=True)


class CreateProduct(graphene.Mutation):
    class Arguments:
        name = graphene.String(required=True)
        description = graphene.String()
        price = graphene.Float(required=True)
        currency = graphene.String(default_value="USD")
        sku = graphene.String(required=True)
        stock_quantity = graphene.Int(default_value=0)
        category_id = graphene.ID(required=True)
        brand = graphene.String()
        tags = graphene.List(graphene.String)
        weight = graphene.Float()
        images = graphene.List(graphene.String)

    product = graphene.Field(ProductType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, name, price, sku, category_id, description=None, currency="USD",
               stock_quantity=0, brand=None, tags=None, weight=None, images=None):
        # Validate category exists
        category = next((c for c in CATEGORIES if c["id"] == category_id), None)
        if not category:
            return CreateProduct(product=None, success=False, message="Category not found")

        # Check SKU uniqueness
        existing_sku = next((p for p in PRODUCTS if p["sku"] == sku), None)
        if existing_sku:
            return CreateProduct(product=None, success=False, message="SKU already exists")

        if price < 0:
            return CreateProduct(product=None, success=False, message="Price must be non-negative")

        now = datetime.utcnow().isoformat()
        new_id = str(max(int(p["id"]) for p in PRODUCTS) + 1)

        new_product = {
            "id": new_id,
            "name": name,
            "description": description or "",
            "price": price,
            "currency": currency,
            "sku": sku,
            "stock_quantity": stock_quantity,
            "category_id": category_id,
            "brand": brand or "",
            "is_active": True,
            "created_at": now,
            "updated_at": now,
            "tags": tags or [],
            "weight": weight or 0,
            "images": images or [],
        }

        PRODUCTS.append(new_product)
        return CreateProduct(product=ProductType(**new_product), success=True, message="Product created successfully")


class UpdateProduct(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)
        name = graphene.String()
        description = graphene.String()
        price = graphene.Float()
        stock_quantity = graphene.Int()
        is_active = graphene.Boolean()
        tags = graphene.List(graphene.String)
        images = graphene.List(graphene.String)

    product = graphene.Field(ProductType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, id, **kwargs):
        product_data = next((p for p in PRODUCTS if p["id"] == id), None)
        if not product_data:
            return UpdateProduct(product=None, success=False, message="Product not found")

        for key, value in kwargs.items():
            if value is not None and key in product_data:
                product_data[key] = value

        product_data["updated_at"] = datetime.utcnow().isoformat()

        return UpdateProduct(product=ProductType(**product_data), success=True, message="Product updated successfully")


class Mutation(graphene.ObjectType):
    create_review = CreateReview.Field()
    update_review = UpdateReview.Field()
    delete_review = DeleteReview.Field()
    vote_review_helpful = VoteReviewHelpful.Field()
    create_product = CreateProduct.Field()
    update_product = UpdateProduct.Field()


